import{_ as e}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as i}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as o,o as l,c as n,a2 as t}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Token API Cloudflare","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Safety/cloudflare-api-token.md","filePath":"pl-PL/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),r={name:"pl-PL/Safety/cloudflare-api-token.md"};function d(s,a,c,p,z,u){return l(),n("div",null,[...a[0]||(a[0]=[t('<h1 id="token-api-cloudflare" tabindex="-1">Token API Cloudflare <a class="header-anchor" href="#token-api-cloudflare" aria-label="Permalink to &quot;Token API Cloudflare&quot;">​</a></h1><p>Dane API Cloudflare pozwalają ImgBed czyścić cache CDN Cloudflare po zmianach plików.</p><p><img src="'+e+'" alt="Ustawienia tokenu API Cloudflare" loading="lazy"></p><h2 id="gdzie-skonfigurowac" tabindex="-1">Gdzie skonfigurować <a class="header-anchor" href="#gdzie-skonfigurowac" aria-label="Permalink to &quot;Gdzie skonfigurować&quot;">​</a></h2><p>Otwórz panel administracyjny, a następnie przejdź do:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Trzeba wypełnić:</p><ul><li>Zone ID</li><li>E-mail konta</li><li>API Key</li></ul><h2 id="co-robi-to-ustawienie" tabindex="-1">Co robi to ustawienie <a class="header-anchor" href="#co-robi-to-ustawienie" aria-label="Permalink to &quot;Co robi to ustawienie&quot;">​</a></h2><p>Cloudflare może cache&#39;ować publiczne URL-e obrazów.</p><p>Cache przyspiesza dostarczanie obrazów, ale może też sprawić, że stara treść będzie widoczna przez jakiś czas po usunięciu, zablokowaniu, zastąpieniu lub przeniesieniu pliku.</p><p>Po skonfigurowaniu danych API Cloudflare ImgBed próbuje wyczyścić powiązany cache Cloudflare po zakończeniu takich operacji.</p><p>Jest to przydatne, gdy:</p><ul><li>usuwasz obraz i chcesz, aby publiczny link przestał działać jak najszybciej.</li><li>blokujesz obraz i chcesz, aby odwiedzający nie widzieli oryginalnego pliku.</li><li>zastępujesz plik o tej samej nazwie i chcesz szybciej pokazać nową wersję.</li><li>przenosisz lub zmieniasz nazwy plików i chcesz szybko odświeżyć cache starych ścieżek.</li><li>zmieniasz reguły publicznego dostępu i chcesz szybciej odświeżyć publiczną galerię albo cache losowych obrazów.</li></ul><h2 id="co-jesli-zostawisz-puste" tabindex="-1">Co jeśli zostawisz puste <a class="header-anchor" href="#co-jesli-zostawisz-puste" aria-label="Permalink to &quot;Co jeśli zostawisz puste&quot;">​</a></h2><p>ImgBed działa normalnie bez tego ustawienia.</p><p>Jedyna różnica polega na tym, że ImgBed nie będzie aktywnie czyścił cache CDN Cloudflare. Odwiedzający mogą widzieć starą zawartość do momentu naturalnego wygaśnięcia cache Cloudflare.</p><h2 id="jak-znalezc-zone-id" tabindex="-1">Jak znaleźć Zone ID <a class="header-anchor" href="#jak-znalezc-zone-id" aria-label="Permalink to &quot;Jak znaleźć Zone ID&quot;">​</a></h2><p>Zone ID to Cloudflare Zone ID strony używanej przez domenę ImgBed.</p><ol><li>Zaloguj się do Cloudflare Dashboard.</li><li>Otwórz stronę, która zawiera domenę ImgBed.</li><li>Znajdź <code>Zone ID</code> na stronie przeglądu.</li><li>Skopiuj je do pola <code>Zone ID</code> w ImgBed.</li></ol><p>To Zone ID strony, nie Account ID.</p><h2 id="e-mail-konta" tabindex="-1">E-mail konta <a class="header-anchor" href="#e-mail-konta" aria-label="Permalink to &quot;E-mail konta&quot;">​</a></h2><p>Wpisz adres e-mail używany do logowania w Cloudflare.</p><p>Musi odpowiadać API Key podanemu poniżej.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Wpisz Cloudflare Global API Key.</p><ol><li>Zaloguj się do Cloudflare Dashboard.</li><li>Otwórz swój profil.</li><li>Przejdź do strony API Tokens.</li><li>Znajdź <code>Global API Key</code>.</li><li>Wyświetl i skopiuj.</li><li>Wklej do pola <code>API Key</code> w ImgBed.</li></ol><p><img src="'+i+'" alt="Wyświetl globalny API key" loading="lazy"></p><h2 id="kiedy-zaczyna-działac" tabindex="-1">Kiedy zaczyna działać <a class="header-anchor" href="#kiedy-zaczyna-działac" aria-label="Permalink to &quot;Kiedy zaczyna działać&quot;">​</a></h2><p>Po wypełnieniu pól zapisz ustawienia.</p><p>Przyszłe zmiany plików będą automatycznie próbowały wyczyścić cache Cloudflare. Operacje wykonane wcześniej nie są czyszczone wstecznie. Jeśli usunięto lub zastąpiono plik przed konfiguracją, poczekaj na wygaśnięcie cache albo wyczyść go ręcznie w Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="czy-to-jest-wymagane" tabindex="-1">Czy to jest wymagane? <a class="header-anchor" href="#czy-to-jest-wymagane" aria-label="Permalink to &quot;Czy to jest wymagane?&quot;">​</a></h3><p>Nie.</p><p>Jeśli domena nie używa Cloudflare albo opóźnienie cache CDN Ci nie przeszkadza, możesz zostawić to puste.</p><h3 id="czy-błedne-dane-zepsuja-upload" tabindex="-1">Czy błędne dane zepsują upload? <a class="header-anchor" href="#czy-błedne-dane-zepsuja-upload" aria-label="Permalink to &quot;Czy błędne dane zepsują upload?&quot;">​</a></h3><p>Zwykle nie.</p><p>Błędne dane uniemożliwią tylko czyszczenie cache Cloudflare. Upload i zwykły dostęp do plików powinny nadal działać.</p><h3 id="dlaczego-usuniety-obraz-nadal-sie-otwiera" tabindex="-1">Dlaczego usunięty obraz nadal się otwiera? <a class="header-anchor" href="#dlaczego-usuniety-obraz-nadal-sie-otwiera" aria-label="Permalink to &quot;Dlaczego usunięty obraz nadal się otwiera?&quot;">​</a></h3><p>Najczęstsza przyczyna to stary plik nadal obecny w cache Cloudflare.</p><p>Przy poprawnych danych API Cloudflare ImgBed czyści cache powiązanego URL-a po usunięciu pliku.</p><h3 id="dlaczego-po-zastapieniu-pliku-nadal-widze-stary-obraz" tabindex="-1">Dlaczego po zastąpieniu pliku nadal widzę stary obraz? <a class="header-anchor" href="#dlaczego-po-zastapieniu-pliku-nadal-widze-stary-obraz" aria-label="Permalink to &quot;Dlaczego po zastąpieniu pliku nadal widzę stary obraz?&quot;">​</a></h3><p>To również zwykle wynika z cache CDN.</p><p>Po skonfigurowaniu tego ustawienia ImgBed próbuje wyczyścić cache starego URL-a, gdy plik o tej samej nazwie zostanie nadpisany.</p>',44)])])}const b=o(r,[["render",d]]);export{k as __pageData,b as default};
